#include <iostream>
#include <memory>
#include <string>
#include <vector>

class Item {
private:
    std::string name;

public:
    Item(std::string n) : name(n) {
        std::cout << "Item " << name << " created" << std::endl;
    }

    ~Item() {
        std::cout << "Item " << name << " destroyed" << std::endl;
    }

    void display() const {
        std::cout << name << std::endl;
    }
};

class Character {
private:
    std::string name;
    std::shared_ptr<Item> item;

public:
    Character(std::string n) : name(n) {
        std::cout << "Character " << name << " created" << std::endl;
    }

    ~Character() {
        std::cout << "Character " << name << " destroyed" << std::endl;
    }

    void setItem(std::shared_ptr<Item> i) {
        item = i;
        std::cout << name << " now has item" << std::endl;
    }

    void display() const {
        std::cout << name;
        if (item) {
            std::cout << " has ";
            item->display();
        } else {
            std::cout << " has no item" << std::endl;
        }
    }
};

int main() {
    std::cout << "=== shared_ptr — Shared Ownership ===" << std::endl;

    // 1. Creating shared_ptr
    std::cout << "\n--- Creating shared_ptr ---" << std::endl;
    auto sword = std::make_shared<Item>("Iron Sword");
    std::cout << "Reference count: " << sword.use_count() << std::endl;

    // 2. Shared ownership
    std::cout << "\n--- Shared ownership ---" << std::endl;
    std::shared_ptr<Item> swordCopy = sword;
    std::cout << "Reference count after copy: " << sword.use_count() << std::endl;

    {
        std::shared_ptr<Item> anotherCopy = sword;
        std::cout << "Reference count inside block: " << sword.use_count() << std::endl;
    }
    std::cout << "Reference count after block: " << sword.use_count() << std::endl;

    // 3. Using shared_ptr with objects
    std::cout << "\n--- Characters with shared items ---" << std::endl;
    auto shield = std::make_shared<Item>("Steel Shield");

    Character hero("Aragorn");
    Character dwarf("Gimli");

    hero.setItem(sword);
    dwarf.setItem(shield);

    hero.display();
    dwarf.display();

    // 4. weak_ptr (non-owning)
    std::cout << "\n--- weak_ptr (non-owning) ---" << std::endl;
    std::weak_ptr<Item> weakItem = sword;
    std::cout << "weak_ptr use_count: " << weakItem.use_count() << std::endl;

    if (auto shared = weakItem.lock()) {
        std::cout << "Item still alive: ";
        shared->display();
    } else {
        std::cout << "Item is gone" << std::endl;
    }

    // 5. Resetting
    std::cout << "\n--- Resetting ---" << std::endl;
    sword.reset();
    std::cout << "After reset, use_count: " << swordCopy.use_count() << std::endl;

    // 6. Cyclic references (danger)
    std::cout << "\n--- Warning: Cyclic references ---" << std::endl;
    std::cout << "shared_ptr can create cycles (A points to B, B points to A)" << std::endl;
    std::cout << "Use weak_ptr to break cycles!" << std::endl;

    // 7. Summary
    std::cout << "\n--- shared_ptr vs unique_ptr ---" << std::endl;
    std::cout << "unique_ptr: exclusive ownership, lightweight" << std::endl;
    std::cout << "shared_ptr: shared ownership, reference counting" << std::endl;
    std::cout << "weak_ptr: non-owning, breaks cycles" << std::endl;

    return 0;
}

