#include <iostream>
#include <memory>

struct Node {
    std::shared_ptr<Node> next;
    ~Node() { std::cout << "Node destroyed" << std::endl; }
};

int main() {
    auto a = std::make_shared<Node>();
    auto b = std::make_shared<Node>();

    // Cycle!
    a->next = b;
    b->next = a;  // Never destroyed!

    std::cout << "Memory leak! Cycle not destroyed." << std::endl;
    return 0;
}

