#include <iostream>
#include <memory>
#include <string>

class Enemy {
private:
    std::string name;

public:
    Enemy(std::string n) : name(n) {
        std::cout << "Enemy " << name << " created!" << std::endl;
    }

    ~Enemy() {
        std::cout << "Enemy " << name << " destroyed!" << std::endl;
    }

    void display() const {
        std::cout << "Enemy: " << name << std::endl;
    }
};

int main() {
    auto enemy = std::make_shared<Enemy>("Goblin");
    std::cout << "Reference count: " << enemy.use_count() << std::endl;

    auto enemy2 = enemy;
    std::cout << "Reference count after copy: " << enemy.use_count() << std::endl;

    std::weak_ptr<Enemy> weak = enemy;
    if (auto shared = weak.lock()) {
        std::cout << "weak_ptr is valid! ";
        shared->display();
    }

    enemy.reset();
    std::cout << "Reference count after reset: " << enemy2.use_count() << std::endl;

    return 0;
}
